-- ----------------------------
-- Table structure for ft_ctrl_list_files
-- ----------------------------
DROP TABLE IF EXISTS `ft_ctrl_list_files`;
CREATE TABLE `ft_ctrl_list_files` (
  `partid` varchar(36) NOT NULL COMMENT '片段ID',
  `fileid` varchar(36) NOT NULL COMMENT '文件ID',
  `filepath` varchar(64) DEFAULT NULL COMMENT '文件路径',
  `filecap` varchar(48) DEFAULT NULL COMMENT '文件显示名称',
  `userid` varchar(36) DEFAULT NULL COMMENT '用户ID',
  `addtime` datetime DEFAULT NULL COMMENT '添加时间',
  `rows` int(11) DEFAULT NULL COMMENT '数据行数',
  `minutes` int(11) DEFAULT NULL COMMENT '消耗时间',
  PRIMARY KEY (`partid`,`fileid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

-- ----------------------------
-- Records of ft_ctrl_list_files
-- ----------------------------

-- ----------------------------
-- Table structure for ft_ctrl_list_files_bind
-- ----------------------------
DROP TABLE IF EXISTS `ft_ctrl_list_files_bind`;
CREATE TABLE `ft_ctrl_list_files_bind` (
  `fileid` varchar(36) NOT NULL COMMENT '文件ID',
  `userid` varchar(36) NOT NULL COMMENT '有权限的用户ID',
  PRIMARY KEY (`fileid`,`userid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

-- ----------------------------
-- Records of ft_ctrl_list_files_bind
-- ----------------------------

-- ----------------------------
-- Table structure for ft_flow_his
-- ----------------------------
DROP TABLE IF EXISTS `ft_flow_his`;
CREATE TABLE `ft_flow_his` (
  `WorkID` varchar(36) NOT NULL COMMENT '原始审批对象ID',
  `FlowID` varchar(36) NOT NULL COMMENT '流程ID',
  `StepValue` int(11) NOT NULL COMMENT '状态值',
  `StepID` int(11) NOT NULL COMMENT '位置值',
  `AlterTime` datetime NOT NULL COMMENT '变更时间',
  `UserID` varchar(36) DEFAULT NULL COMMENT '操作用户ID',
  `Result` varchar(50) DEFAULT NULL COMMENT '审批结果',
  `Mimo` varchar(255) DEFAULT NULL COMMENT '审批备注说明',
  `StepCaption` varchar(128) DEFAULT NULL COMMENT '位置值显示',
  `IsEnd` smallint(6) NOT NULL COMMENT '是否为终结节点',
  `IsStart` smallint(6) NOT NULL COMMENT '是否为起始节点',
  `IsFinished` smallint(6) NOT NULL COMMENT '是否已结束（取消，拒绝等）',
  PRIMARY KEY (`WorkID`,`FlowID`,`StepValue`,`StepID`,`AlterTime`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='流程历史记录';

-- ----------------------------
-- Records of ft_flow_his
-- ----------------------------

-- ----------------------------
-- Table structure for ft_flow_list
-- ----------------------------
DROP TABLE IF EXISTS `ft_flow_list`;
CREATE TABLE `ft_flow_list` (
  `FlowID` varchar(36) NOT NULL COMMENT '流程ID',
  `FlowName` varchar(64) DEFAULT NULL COMMENT '流程名称',
  `DicCode` varchar(50) DEFAULT NULL COMMENT '类型字典ID',
  `Mimo` varchar(255) DEFAULT NULL COMMENT '备注说明',
  `OrderRank` int(11) DEFAULT NULL COMMENT '排序值',
  `MainTable` varchar(255) DEFAULT NULL COMMENT '主表表名',
  `MainTableKey` varchar(255) DEFAULT NULL COMMENT '主表主键列名',
  `FlowDefine` longtext COMMENT '流程定义XML',
  `EndOperation` longtext COMMENT '结束时的操作，换行添加多个',
  `RejectStatValue` int(11) DEFAULT NULL COMMENT '被拒绝状态值',
  `CancelStatValue` int(11) DEFAULT NULL COMMENT '取消的状态值',
  `StatColumn` varchar(255) DEFAULT NULL COMMENT '状态值写入列（若需要）',
  `StatCaptionColumn` varchar(255) DEFAULT NULL COMMENT '状态值显示写入列（若需要）',
  `StatCaptionEnum` longtext COMMENT '状态值及其显示的枚举',
  `pid` varchar(36) DEFAULT NULL COMMENT '父表单ID',
  `fmem` varchar(36) DEFAULT NULL COMMENT '添加用户',
  `modfmem` varchar(36) DEFAULT NULL COMMENT '修改用户',
  `addtime` datetime DEFAULT NULL COMMENT '添加时间',
  `updatetime` datetime DEFAULT NULL COMMENT '修改时间',
  `dydata` varchar(255) DEFAULT NULL COMMENT '多行标记',
  `stat` smallint(6) DEFAULT NULL COMMENT '删除状态',
  `flow` int(11) DEFAULT NULL COMMENT '流程状态',
  `flowpos` int(11) DEFAULT NULL COMMENT '流程位置',
  PRIMARY KEY (`FlowID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='流程列表';

-- ----------------------------
-- Records of ft_flow_list
-- ----------------------------
