-- ----------------------------
-- Table structure for ft_flow_next
-- ----------------------------
DROP TABLE IF EXISTS `ft_flow_next`;
CREATE TABLE `ft_flow_next` (
  `WorkID` varchar(36) NOT NULL COMMENT '原始审批对象ID',
  `FlowID` varchar(36) NOT NULL COMMENT '流程ID',
  `StepValue` int(11) DEFAULT NULL COMMENT '状态值',
  `StepID` int(11) DEFAULT NULL COMMENT '位置值',
  `AddTime` datetime DEFAULT NULL COMMENT '添加时间',
  `StepCaption` varchar(128) DEFAULT NULL COMMENT '位置值显示',
  PRIMARY KEY (`WorkID`,`FlowID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='下一步流程信息';

-- ----------------------------
-- Records of ft_flow_next
-- ----------------------------

-- ----------------------------
-- Table structure for ft_flow_next_user
-- ----------------------------
DROP TABLE IF EXISTS `ft_flow_next_user`;
CREATE TABLE `ft_flow_next_user` (
  `WorkID` varchar(36) NOT NULL COMMENT '原始审批对象ID',
  `FlowID` varchar(36) NOT NULL COMMENT '流程ID',
  `UserID` varchar(36) NOT NULL COMMENT '待审批用户',
  PRIMARY KEY (`WorkID`,`FlowID`,`UserID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='下一步流程审批人';

-- ----------------------------
-- Records of ft_flow_next_user
-- ----------------------------

-- ----------------------------
-- Table structure for ft_ftdp_apidoc
-- ----------------------------
DROP TABLE IF EXISTS `ft_ftdp_apidoc`;
CREATE TABLE `ft_ftdp_apidoc` (
  `FId` varchar(36) NOT NULL COMMENT '主键ID',
  `ApiPath` varchar(250) NOT NULL COMMENT 'api路径',
  `PageID` varchar(50) DEFAULT NULL COMMENT '页面ID',
  `PageCaption` varchar(50) DEFAULT NULL COMMENT '页面标题',
  `DevUser` varchar(90) DEFAULT NULL COMMENT '开发者',
  `ApiType` varchar(10) DEFAULT NULL COMMENT 'api类型',
  `Mimo` varchar(250) DEFAULT NULL COMMENT '备注',
  `InputDesc` longtext COMMENT '输入描述',
  `OutputDesc` longtext COMMENT '输出描述',
  `ModTime` datetime DEFAULT NULL COMMENT '更新时间',
  `PostManJson` longtext COMMENT 'PostMan导入Json',
  PRIMARY KEY (`FId`,`ApiPath`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

-- ----------------------------
-- Records of ft_ftdp_apidoc
-- ----------------------------
