-- ----------------------------
-- Table structure for ft_ftdp_apiset
-- ----------------------------
DROP TABLE IF EXISTS `ft_ftdp_apiset`;
CREATE TABLE `ft_ftdp_apiset` (
  `ApiPath` varchar(250) NOT NULL COMMENT 'api路径',
  `PartID` varchar(50) DEFAULT NULL COMMENT '片段ID',
  `PageID` varchar(50) DEFAULT NULL COMMENT '页面ID',
  `ApiType` varchar(10) DEFAULT NULL COMMENT 'api类型',
  `Set_List_Order` varchar(150) DEFAULT NULL COMMENT '列表排序',
  `Set_List_Sql` text COMMENT '列表SQL',
  `Set_List_SqlCount` text,
  `Set_List_CusCondition` text,
  `Set_List_RowAll` longtext COMMENT '列表列定义',
  `Set_DyValue_DefineStr` longtext COMMENT '数据获取定义',
  `Set_DyValue_ApiDefine` longtext COMMENT '数据获取api定义',
  `Set_DyValue_DefaultFID` varchar(50) DEFAULT NULL COMMENT '数据获取默认主键值',
  `Set_DyValue_FidCol` varchar(50) DEFAULT NULL COMMENT '数据获取主键列名',
  `Set_DyValue_OpDefaultCol` smallint(6) DEFAULT NULL COMMENT '数据获取保留字段',
  PRIMARY KEY (`ApiPath`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

-- ----------------------------
-- Records of ft_ftdp_apiset
-- ----------------------------
